import { useState, useEffect, useRef } from 'react'
import { NavLink, useNavigate } from 'react-router-dom'
import { toast } from 'react-hot-toast'
import { useAuth } from '../context/AuthContext'
import { useTheme } from '../context/ThemeContext'
import { useLang } from '../context/LangContext'
import { api } from '../lib/api'

const LANGS = [
  { code: 'en', flag: '🇬🇧', label: 'EN'  },
  { code: 'hi', flag: '🇮🇳', label: 'हि'  },
  { code: 'mr', flag: '🇮🇳', label: 'म'   },
]

export default function Navbar() {
  const { user, logout } = useAuth()
  const { theme, toggle } = useTheme()
  const { lang, setLang, t } = useLang()
  const navigate = useNavigate()
  const [open, setOpen]         = useState(false)
  const [langOpen, setLangOpen] = useState(false)
  const [notifsOpen, setNotifsOpen] = useState(false)
  const [unread, setUnread]     = useState(0)
  const [unreadNotifs, setUnreadNotifs] = useState(0)
  const [notifs, setNotifs]     = useState([])
  const langRef                  = useRef(null)
  const notifsRef                = useRef(null)

  // Close dropdowns when clicking outside
  useEffect(() => {
    const handler = e => {
      if (langRef.current && !langRef.current.contains(e.target)) setLangOpen(false)
      if (notifsRef.current && !notifsRef.current.contains(e.target)) setNotifsOpen(false)
    }
    document.addEventListener('mousedown', handler)
    return () => document.removeEventListener('mousedown', handler)
  }, [])

  const close = () => { setOpen(false); setLangOpen(false) }

  // Poll unread messages & notifications when logged in
  useEffect(() => {
    if (!user) { setUnread(0); setUnreadNotifs(0); return }
    const poll = async () => {
      try {
        const [msgRes, notifRes] = await Promise.all([
          api('/api/messages/unread'),
          api('/api/notifications?filter=unread')
        ])
        setUnread(msgRes.count || 0)
        setUnreadNotifs(notifRes.unreadCount || 0)
        if (notifsOpen) {
          const all = await api('/api/notifications')
          setNotifs(all.notifications || [])
        } else {
          setNotifs(notifRes.notifications || [])
        }
      } catch {}
    }
    poll()
    const id = setInterval(poll, 15000) // every 15s
    return () => clearInterval(id)
  }, [user, notifsOpen])

  const handleNotifsToggle = async () => {
    setNotifsOpen(o => {
      if (!o) { // opening
        api('/api/notifications').then(d => setNotifs(d.notifications || [])).catch(()=>{})
      }
      return !o
    })
  }

  const markRead = async (id, link) => {
    try {
      await api(`/api/notifications/${id}/read`, { method: 'PUT' })
      setNotifs(ns => ns.map(n => n.id === id ? { ...n, is_read: 1 } : n))
      setUnreadNotifs(u => Math.max(0, u - 1))
      setNotifsOpen(false)
      if (link) navigate(link)
    } catch {}
  }

  const markAllRead = async () => {
    try {
      await api('/api/notifications/read-all', { method: 'PUT' })
      setNotifs(ns => ns.map(n => ({ ...n, is_read: 1 })))
      setUnreadNotifs(0)
    } catch {}
  }

  const handleLogout = async () => {
    await logout()
    toast.success('Logged out. See you soon! 👋')
    navigate('/')
    close()
  }

  const handleLang = (code) => {
    setLang(code, !!user)  // persist to DB if logged in
    setLangOpen(false)
  }

  const currentLang = LANGS.find(l => l.code === lang) || LANGS[0]

  return (
    <nav className="navbar">
      <div className="navbar-brand" onClick={() => { navigate('/'); close() }}>
        <div className="logo-icon">W</div>
        <span>Workify</span>
      </div>

      <button className="mobile-toggle" onClick={() => setOpen(o => !o)} aria-label="Toggle menu">
        <span /><span /><span />
      </button>

      <ul className={`navbar-nav${open ? ' open' : ''}`}>
        {!user ? (
          <>
            <li><NavLink to="/login"  onClick={close}>{t('login')}</NavLink></li>
            <li><NavLink to="/signup" onClick={close} className="btn btn-primary btn-sm">{t('signup')}</NavLink></li>
          </>
        ) : (
          <>
            {user.role === 'seeker' && <>
              <li><NavLink to="/dashboard"    onClick={close}>{t('dashboard')}</NavLink></li>
              <li><NavLink to="/jobs"         onClick={close}>{t('findJobs')}</NavLink></li>
              <li><NavLink to="/applications" onClick={close}>{t('applications')}</NavLink></li>
              <li>
                <NavLink to="/messages" onClick={close} className="nav-msg-link">
                  💬 {t('messages')}
                  {unread > 0 && <span className="nav-unread-badge">{unread > 9 ? '9+' : unread}</span>}
                </NavLink>
              </li>
              <li><NavLink to="/profile" onClick={close}>{t('profile')}</NavLink></li>
            </>}
            {user.role === 'employer' && <>
              <li><NavLink to="/dashboard" onClick={close}>{t('dashboard')}</NavLink></li>
              <li><NavLink to="/post-job"  onClick={close}>{t('postJob')}</NavLink></li>
              <li><NavLink to="/my-jobs"   onClick={close}>{t('myJobs')}</NavLink></li>
              <li>
                <NavLink to="/messages" onClick={close} className="nav-msg-link">
                  💬 {t('messages')}
                  {unread > 0 && <span className="nav-unread-badge">{unread > 9 ? '9+' : unread}</span>}
                </NavLink>
              </li>
              <li><NavLink to="/profile" onClick={close}>{t('profile')}</NavLink></li>
            </>}
            {user.role === 'admin' && <>
              <li><NavLink to="/dashboard" onClick={close}>{t('dashboard')}</NavLink></li>
              <li><NavLink to="/admin"     onClick={close}>{t('adminPanel')}</NavLink></li>
            </>}

            {/* Notifications Dropdown */}
            <li className="lang-selector-wrap" ref={notifsRef}>
              <button className="lang-btn" onClick={handleNotifsToggle} style={{ position: 'relative' }}>
                🔔
                {unreadNotifs > 0 && <span className="nav-unread-badge" style={{ top: -5, right: -5 }}>{unreadNotifs > 9 ? '9+' : unreadNotifs}</span>}
              </button>
              {notifsOpen && (
                <div className="lang-dropdown notifications-dropdown" style={{ width: 300, right: 0, padding: 0, overflow: 'hidden' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', padding: '12px 16px', borderBottom: '1px solid var(--border)', background: 'var(--surface-solid)' }}>
                    <h4 style={{ margin: 0, fontSize: '0.95rem' }}>{t('notifications')}</h4>
                    {unreadNotifs > 0 && (
                      <button onClick={markAllRead} style={{ background: 'none', border: 'none', color: 'var(--primary)', cursor: 'pointer', fontSize: '0.8rem', fontWeight: 600 }}>
                        {t('markAllRead')}
                      </button>
                    )}
                  </div>
                  <div style={{ maxHeight: '350px', overflowY: 'auto' }}>
                    {notifs.length === 0 ? (
                      <div style={{ padding: 24, textAlign: 'center', color: 'var(--text-muted)' }}>
                        <span style={{ fontSize: '2rem' }}>🔕</span>
                        <p style={{ marginTop: 8, fontSize: '0.9rem' }}>{t('noNotifications')}</p>
                      </div>
                    ) : (
                      notifs.map(n => (
                        <div 
                          key={n.id} 
                          onClick={() => markRead(n.id, n.link)}
                          style={{ 
                            padding: '12px 16px', 
                            borderBottom: '1px solid var(--border-light)',
                            background: n.is_read ? 'transparent' : 'rgba(var(--primary-rgb), 0.05)',
                            cursor: 'pointer',
                            transition: 'background var(--t-fast)'
                          }}
                        >
                          <div style={{ fontSize: '0.88rem', fontWeight: n.is_read ? 400 : 600, marginBottom: 4 }}>
                            {n.type === 'alert' ? '⚠️ ' : n.type === 'status' ? '📋 ' : '🔔 '}
                            {n.message}
                          </div>
                          <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>
                            {new Date(n.created_at + 'Z').toLocaleString('en-IN')}
                          </div>
                        </div>
                      ))
                    )}
                  </div>
                </div>
              )}
            </li>

            <li><button className="btn btn-outline btn-sm" onClick={handleLogout}>{t('logout')}</button></li>
          </>
        )}

        {/* Lang selector */}
        <li className="lang-selector-wrap" ref={langRef}>
          <button className="lang-btn" onClick={() => setLangOpen(o => !o)}>
            {currentLang.flag} {currentLang.label} ▾
          </button>
          {langOpen && (
            <div className="lang-dropdown">
              {LANGS.map(l => (
                <button key={l.code}
                  className={`lang-option${lang === l.code ? ' active' : ''}`}
                  onClick={() => handleLang(l.code)}>
                  {l.flag} {l.code === 'en' ? 'English' : l.code === 'hi' ? 'हिन्दी' : 'मराठी'}
                </button>
              ))}
            </div>
          )}
        </li>

        {/* Theme toggle */}
        <li>
          <button className="theme-toggle" onClick={toggle} title="Toggle theme">
            {theme === 'dark' ? '☀️' : '🌙'}
          </button>
        </li>
      </ul>
    </nav>
  )
}

import { createContext, useContext, useState, useEffect, useCallback } from 'react'
import { api } from '../lib/api'

const AuthContext = createContext(null)

export function AuthProvider({ children }) {
  const [user, setUser]       = useState(null)
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    api('/api/auth/me')
      .then(d => setUser(d.user))
      .catch(() => setUser(null))
      .finally(() => setLoading(false))
  }, [])

  const login = useCallback(async (email, password) => {
    const d = await api('/api/auth/login', { method: 'POST', body: { email, password } })
    setUser(d.user)
    return d.user
  }, [])

  const signup = useCallback(async (body) => {
    const d = await api('/api/auth/signup', { method: 'POST', body })
    setUser(d.user)
    return d.user
  }, [])

  const logout = useCallback(async () => {
    await api('/api/auth/logout', { method: 'POST' })
    setUser(null)
    // Clear session-level lang preference
    try { sessionStorage.removeItem('w-lang') } catch {}
  }, [])

  const updateUser = useCallback((patch) => {
    setUser(u => ({ ...u, ...patch }))
  }, [])

  return (
    <AuthContext.Provider value={{ user, loading, login, signup, logout, updateUser }}>
      {children}
    </AuthContext.Provider>
  )
}

export function useAuth() {
  const ctx = useContext(AuthContext)
  if (!ctx) throw new Error('useAuth must be inside AuthProvider')
  return ctx
}

import { createContext, useContext, useState, useEffect, useCallback } from 'react'
import T from '../lib/translations'

const LangContext = createContext(null)

// Auto-detect from browser — no localStorage!
function detectLang() {
  const lang = (navigator.language || navigator.userLanguage || 'en').toLowerCase()
  if (lang.startsWith('hi')) return 'hi'
  if (lang.startsWith('mr')) return 'mr'
  return 'en'
}

export function LangProvider({ children }) {
  // Use sessionStorage as fallback for guests (clears when tab closes — NOT persistent localStorage)
  const [lang, setLangState] = useState(() => {
    try { return sessionStorage.getItem('w-lang') || detectLang() } catch { return detectLang() }
  })

  // Apply font + lang attribute whenever lang changes
  useEffect(() => {
    document.documentElement.setAttribute('lang', lang)
    if (lang !== 'en') {
      document.body.classList.add('devanagari')
    } else {
      document.body.classList.remove('devanagari')
    }
  }, [lang])

  // setLang — persists to DB if logged in, else sessionStorage
  const setLang = useCallback(async (newLang, isLoggedIn = false) => {
    setLangState(newLang)
    try { sessionStorage.setItem('w-lang', newLang) } catch {}
    if (isLoggedIn) {
      // Persist to DB (no localStorage needed)
      try {
        await fetch('/api/auth/lang', {
          method: 'PUT',
          credentials: 'include',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ lang: newLang })
        })
      } catch {} // silent — not critical
    }
  }, [])

  // Called after login — sync lang from user.lang_pref (from DB)
  const syncLangFromUser = useCallback((user) => {
    if (user?.lang_pref && user.lang_pref !== 'auto' && ['en','hi','mr'].includes(user.lang_pref)) {
      setLangState(user.lang_pref)
      try { sessionStorage.setItem('w-lang', user.lang_pref) } catch {}
    }
  }, [])

  const t = (key) => {
    if (!T[key]) return key
    return T[key][lang] || T[key]['en'] || key
  }

  const tCat = (catId) => {
    const map = {
      'All': t('catAll'), 'Construction': t('catConstruction'),
      'Domestic': t('catDomestic'), 'Delivery': t('catDelivery'),
      'Agriculture': t('catAgriculture'), 'Kitchen': t('catKitchen'),
      'Cleaning': t('catCleaning'), 'Warehouse': t('catWarehouse'),
      'Repair': t('catRepair'), 'General': t('catGeneral'),
    }
    return map[catId] || catId
  }

  return (
    <LangContext.Provider value={{ lang, setLang, syncLangFromUser, t, tCat }}>
      {children}
    </LangContext.Provider>
  )
}

export function useLang() {
  const ctx = useContext(LangContext)
  if (!ctx) throw new Error('useLang must be inside LangProvider')
  return ctx
}

import { createContext, useContext, useState, useEffect } from 'react'

const ThemeContext = createContext(null)

export function ThemeProvider({ children }) {
  const [theme, setTheme] = useState(() => localStorage.getItem('workify-theme') || 'dark')

  useEffect(() => {
    document.documentElement.setAttribute('data-theme', theme)
    localStorage.setItem('workify-theme', theme)
  }, [theme])

  const toggle = () => setTheme(t => t === 'dark' ? 'light' : 'dark')

  return (
    <ThemeContext.Provider value={{ theme, toggle }}>
      {children}
    </ThemeContext.Provider>
  )
}

export function useTheme() {
  return useContext(ThemeContext)
}

import { useEffect, useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { toast } from 'react-hot-toast'
import { useAuth } from '../context/AuthContext'
import { useLang } from '../context/LangContext'
import { api } from '../lib/api'
import { Spinner, CatBadgeSm, UrgencyLabel, Badge } from '../components/UI'
import ConfirmModal from '../components/ConfirmModal'

const TABS = ['users', 'jobs', 'smtp', 'mail']

export default function Admin() {
  const { user, loading: authLoading } = useAuth()
  const { t } = useLang()
  const navigate = useNavigate()
  const [tab, setTab] = useState('users')
  const [data, setData] = useState(null)
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    if (!authLoading && (!user || user.role !== 'admin')) { navigate('/dashboard'); return }
  }, [user, authLoading, navigate])

  useEffect(() => {
    if (!user) return
    setLoading(true)
    setData(null)
    const routes = { users: '/api/admin/users', jobs: '/api/admin/jobs', smtp: '/api/admin/smtp', mail: null }
    if (!routes[tab]) { setLoading(false); return }
    api(routes[tab]).then(d => setData(d)).catch(() => {}).finally(() => setLoading(false))
  }, [tab, user])

  if (authLoading) return <div className="container"><Spinner /></div>
  if (!user || user.role !== 'admin') return null

  const tabLabels = {
    users: t('tabUsers'),
    jobs:  t('tabJobs'),
    smtp:  t('tabSmtp'),
    mail:  t('tabMail'),
  }

  return (
    <div className="container">
      <div className="page-header">
        <h1>{t('adminTitle')}</h1>
        <p>{t('adminSubtitle')}</p>
      </div>

      <div className="admin-tabs">
        {TABS.map(tb => (
          <button key={tb} className={`admin-tab${tab === tb ? ' active' : ''}`} onClick={() => setTab(tb)}>
            {tabLabels[tb]}
          </button>
        ))}
      </div>

      {tab === 'mail' ? (
        <MailTab />
      ) : loading ? <Spinner /> : (
        <div className="admin-section">
          {tab === 'users' && <UsersTab users={data?.users || []} reload={() => setTab(t => { setData(null); return t })} />}
          {tab === 'jobs'  && <JobsTab  jobs={data?.jobs   || []} reload={() => setTab(t => { setData(null); return t })} />}
          {tab === 'smtp'  && <SmtpTab  settings={data?.settings || {}} />}
        </div>
      )}
    </div>
  )
}

